import{c as a,Q as i,j as r,m as t}from"./chunks/framework.BPKcPtvA.js";const c=JSON.parse('{"title":"定期重复任务","description":"","frontmatter":{},"headers":[],"relativePath":"using-system/task-management/repeat-task/index.md","filePath":"using-system/task-management/repeat-task/index.md"}'),e={name:"using-system/task-management/repeat-task/index.md"};function o(n,l,s,h,u,d){return i(),r("div",null,[...l[0]||(l[0]=[t('<h1 id="定期重复任务" tabindex="-1">定期重复任务 <a class="header-anchor" href="#定期重复任务" aria-label="Permalink to &quot;定期重复任务&quot;">​</a></h1><p>创建需要按固定周期执行的投后管理任务，系统会自动按照设定的规则生成任务实例，无需手动重复创建。</p><h2 id="功能概述" tabindex="-1">功能概述 <a class="header-anchor" href="#功能概述" aria-label="Permalink to &quot;功能概述&quot;">​</a></h2><p>适用于投后管理中需要周期性执行的工作场景，例如：</p><ul><li><strong>风险评估</strong>：每月对投资企业进行风险评估</li><li><strong>季度财务审阅</strong>：每季度审阅投资企业财务报表</li><li><strong>董事会筹备</strong>：每季度董事会召开前的筹备工作</li><li><strong>半年度经营分析</strong>：每半年分析企业经营状况</li><li><strong>合规检查</strong>：每半年进行一次合规性检查</li><li><strong>年度投后检查</strong>：每年对投资企业进行全面投后检查</li></ul><h2 id="重复类型" tabindex="-1">重复类型 <a class="header-anchor" href="#重复类型" aria-label="Permalink to &quot;重复类型&quot;">​</a></h2><p>系统支持以下重复类型：</p><h3 id="按天重复" tabindex="-1">按天重复 <a class="header-anchor" href="#按天重复" aria-label="Permalink to &quot;按天重复&quot;">​</a></h3><ul><li><strong>每天</strong>：每天生成一次任务</li><li><strong>工作日</strong>：仅在工作日（周一至周五）生成任务</li><li><strong>自定义天数</strong>：每N天重复一次（如每3天、每7天）</li></ul><h3 id="按周重复" tabindex="-1">按周重复 <a class="header-anchor" href="#按周重复" aria-label="Permalink to &quot;按周重复&quot;">​</a></h3><ul><li><strong>每周</strong>：每周重复一次</li><li><strong>自定义周数</strong>：每N周重复一次（如每2周、每4周）</li><li><strong>选择星期</strong>：可选择具体的星期几（如每周一、每周三、每周五）</li></ul><h3 id="按月重复" tabindex="-1">按月重复 <a class="header-anchor" href="#按月重复" aria-label="Permalink to &quot;按月重复&quot;">​</a></h3><ul><li><strong>每月</strong>：每月重复一次</li><li><strong>自定义月数</strong>：每N月重复一次（如每2个月、每6个月）</li><li><strong>选择日期</strong>：可选择每月的具体日期（如每月1号、每月15号）</li><li><strong>按星期</strong>：按每月的第几个星期几（如每月第一个周一、每月最后一个周五）</li></ul><h3 id="按年重复" tabindex="-1">按年重复 <a class="header-anchor" href="#按年重复" aria-label="Permalink to &quot;按年重复&quot;">​</a></h3><ul><li><strong>每年</strong>：每年重复一次</li><li><strong>自定义年数</strong>：每N年重复一次（如每0.5年、每2年）</li><li><strong>选择日期</strong>：可选择具体的月日（如每年1月1日、每年6月30日）</li></ul><h2 id="创建定期重复任务" tabindex="-1">创建定期重复任务 <a class="header-anchor" href="#创建定期重复任务" aria-label="Permalink to &quot;创建定期重复任务&quot;">​</a></h2><h3 id="操作步骤" tabindex="-1">操作步骤 <a class="header-anchor" href="#操作步骤" aria-label="Permalink to &quot;操作步骤&quot;">​</a></h3><ol><li><p><strong>进入任务创建窗口页面，设置重复规则</strong></p><ul><li><p>选择重复类型（按天/按周/按月/按年） <img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260522183725340.png" alt=""></p></li><li><p>也可在任务设置中找到「自定义时间」选项 <img src="https://cdn.songlin.site/%E5%B7%A5%E4%BD%9C/%E8%B5%84%E7%AE%A1%E9%A1%B9%E7%9B%AE/20260522183834694.png" alt=""></p></li></ul></li><li><p><strong>后续，配置其他参数</strong></p><ul><li>设置任务提醒：配置通知时间、通知方式和通知对象 <ul><li><strong>通知时间</strong>：设置任务生成时间（如每月1日上午9:00）和首次提醒时间（如生成后立即提醒）</li><li><strong>通知方式</strong>：选择系统通知、邮件、短信、微信等通知渠道</li><li><strong>通知对象</strong>：指定负责人、参与人、审批人等需要收到通知的人员</li></ul></li></ul></li><li><p><strong>保存任务</strong></p><ul><li>点击「保存」按钮</li><li>系统将自动生成第一个任务实例</li></ul></li></ol><h2 id="重复任务管理" tabindex="-1">重复任务管理 <a class="header-anchor" href="#重复任务管理" aria-label="Permalink to &quot;重复任务管理&quot;">​</a></h2><h3 id="查看重复任务" tabindex="-1">查看重复任务 <a class="header-anchor" href="#查看重复任务" aria-label="Permalink to &quot;查看重复任务&quot;">​</a></h3><ul><li>在任务列表中，重复任务会显示特殊的重复图标 🔄</li><li>点击任务可查看重复规则和所有生成的实例</li><li>在任务详情页可以看到「重复规则」和「任务实例」两个标签页</li></ul><h3 id="编辑重复规则" tabindex="-1">编辑重复规则 <a class="header-anchor" href="#编辑重复规则" aria-label="Permalink to &quot;编辑重复规则&quot;">​</a></h3><ol><li>打开重复任务详情页</li><li>点击「编辑」按钮</li><li>修改重复规则</li><li>保存后，新的规则将应用于未来生成的任务实例</li></ol><h3 id="停止重复" tabindex="-1">停止重复 <a class="header-anchor" href="#停止重复" aria-label="Permalink to &quot;停止重复&quot;">​</a></h3><ul><li><strong>立即停止</strong>：在任务详情页点击「停止重复」按钮，不再生成新的任务实例</li><li><strong>设置结束日期</strong>：在创建或编辑时设置结束日期，到达日期后自动停止</li><li><strong>完成次数限制</strong>：设置最大完成次数，达到次数后自动停止</li></ul><h3 id="删除重复任务" tabindex="-1">删除重复任务 <a class="header-anchor" href="#删除重复任务" aria-label="Permalink to &quot;删除重复任务&quot;">​</a></h3><ul><li>删除重复任务将同时删除所有未完成和已完成的任务实例</li><li>已删除的任务无法恢复，请谨慎操作</li></ul><h2 id="任务实例管理" tabindex="-1">任务实例管理 <a class="header-anchor" href="#任务实例管理" aria-label="Permalink to &quot;任务实例管理&quot;">​</a></h2><h3 id="查看任务实例" tabindex="-1">查看任务实例 <a class="header-anchor" href="#查看任务实例" aria-label="Permalink to &quot;查看任务实例&quot;">​</a></h3><p>在重复任务详情页的「任务实例」标签页中，可以查看：</p><ul><li>所有已生成的任务实例列表</li><li>每个实例的状态（待处理、进行中、已完成、已逾期）</li><li>每个实例的负责人和截止时间</li><li>每个实例的完成时间</li></ul><h3 id="处理单个实例" tabindex="-1">处理单个实例 <a class="header-anchor" href="#处理单个实例" aria-label="Permalink to &quot;处理单个实例&quot;">​</a></h3><ul><li><strong>完成任务</strong>：标记单个任务实例为已完成</li><li><strong>编辑实例</strong>：修改单个任务实例的内容（不影响其他实例）</li><li><strong>删除实例</strong>：删除单个任务实例（不影响重复规则和其他实例）</li><li><strong>跳过实例</strong>：跳过本次任务，下次继续按规则生成</li></ul><h3 id="批量操作" tabindex="-1">批量操作 <a class="header-anchor" href="#批量操作" aria-label="Permalink to &quot;批量操作&quot;">​</a></h3><ul><li><strong>批量完成</strong>：选择多个实例，批量标记为已完成</li><li><strong>批量分配</strong>：将多个实例分配给同一负责人</li><li><strong>批量删除</strong>：删除选中的多个任务实例</li></ul><h2 id="高级设置" tabindex="-1">高级设置 <a class="header-anchor" href="#高级设置" aria-label="Permalink to &quot;高级设置&quot;">​</a></h2><h3 id="排除特定日期" tabindex="-1">排除特定日期 <a class="header-anchor" href="#排除特定日期" aria-label="Permalink to &quot;排除特定日期&quot;">​</a></h3><p>在设置重复规则时，可以排除特定日期：</p><ul><li><strong>排除节假日</strong>：系统会自动识别法定节假日，不在节假日生成任务</li><li><strong>自定义排除日期</strong>：手动选择不需要生成任务的日期</li><li><strong>排除规则</strong>：设置排除规则（如排除周末、排除特定月份）</li></ul><h3 id="提醒设置" tabindex="-1">提醒设置 <a class="header-anchor" href="#提醒设置" aria-label="Permalink to &quot;提醒设置&quot;">​</a></h3><p>为重复任务设置提醒，确保执行对象及时收到通知：</p><h4 id="通知时间设置" tabindex="-1">通知时间设置 <a class="header-anchor" href="#通知时间设置" aria-label="Permalink to &quot;通知时间设置&quot;">​</a></h4><ul><li><strong>任务生成时间</strong>：设置任务实例的生成时间（如每天上午9:00、每周一上午10:00）</li><li><strong>首次提醒时间</strong>：任务生成后多久发送首次提醒（如生成后立即提醒、生成后1小时提醒）</li><li><strong>重复提醒间隔</strong>：在任务截止前的提醒频率（如每天提醒一次、每3天提醒一次）</li><li><strong>截止前提醒</strong>：任务截止前特定时间发送提醒（如截止前1天、截止前3天）</li></ul><h4 id="通知方式" tabindex="-1">通知方式 <a class="header-anchor" href="#通知方式" aria-label="Permalink to &quot;通知方式&quot;">​</a></h4><ul><li><strong>系统通知</strong>：通过系统消息中心发送通知</li><li><strong>邮件通知</strong>：发送邮件到执行对象的邮箱</li><li><strong>短信通知</strong>：发送短信到执行对象的手机</li><li><strong>微信通知</strong>：通过企业微信或微信发送通知</li></ul><h4 id="通知对象" tabindex="-1">通知对象 <a class="header-anchor" href="#通知对象" aria-label="Permalink to &quot;通知对象&quot;">​</a></h4><ul><li><strong>负责人</strong>：任务的直接负责人</li><li><strong>参与人</strong>：任务的参与人员</li><li><strong>审批人</strong>：任务的审批人员</li><li><strong>抄送人员</strong>：需要知晓任务进展的其他人员</li></ul><h3 id="依赖关系" tabindex="-1">依赖关系 <a class="header-anchor" href="#依赖关系" aria-label="Permalink to &quot;依赖关系&quot;">​</a></h3><p>设置任务实例之间的依赖关系：</p><ul><li><strong>前置任务</strong>：当前任务实例完成后才能生成下一个实例</li><li><strong>后置任务</strong>：当前任务实例完成后自动触发其他任务</li></ul><h2 id="注意事项" tabindex="-1">注意事项 <a class="header-anchor" href="#注意事项" aria-label="Permalink to &quot;注意事项&quot;">​</a></h2><h3 id="时间设置" tabindex="-1">时间设置 <a class="header-anchor" href="#时间设置" aria-label="Permalink to &quot;时间设置&quot;">​</a></h3><ul><li>确保设置正确的时区，避免任务生成时间错误</li><li>建议在非工作时间生成任务，避免影响系统性能</li><li>考虑节假日和工作日，合理设置重复规则</li></ul><h3 id="任务分配" tabindex="-1">任务分配 <a class="header-anchor" href="#任务分配" aria-label="Permalink to &quot;任务分配&quot;">​</a></h3><ul><li>为重复任务设置默认负责人</li><li>如果负责人有变动，及时更新任务分配</li><li>可以设置负责人轮换规则（如每周轮换一次）</li></ul><h3 id="性能考虑" tabindex="-1">性能考虑 <a class="header-anchor" href="#性能考虑" aria-label="Permalink to &quot;性能考虑&quot;">​</a></h3><ul><li>避免创建过多重复任务，可能影响系统性能</li><li>定期清理已完成的历史任务实例</li><li>合理设置重复频率，避免任务堆积</li></ul><h3 id="数据备份" tabindex="-1">数据备份 <a class="header-anchor" href="#数据备份" aria-label="Permalink to &quot;数据备份&quot;">​</a></h3><ul><li>重要重复任务建议定期备份</li><li>删除重复任务前，确认是否需要保留历史数据</li><li>可以导出任务实例记录进行存档</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><h3 id="q-重复任务没有按时生成怎么办" tabindex="-1">Q：重复任务没有按时生成怎么办？ <a class="header-anchor" href="#q-重复任务没有按时生成怎么办" aria-label="Permalink to &quot;Q：重复任务没有按时生成怎么办？&quot;">​</a></h3><p>A：请检查以下设置：</p><ul><li>确认重复规则是否正确设置</li><li>检查系统时间是否准确</li><li>确认任务是否被暂停或停止</li><li>查看系统日志，排查是否有错误</li></ul><h3 id="q-如何修改已生成的任务实例" tabindex="-1">Q：如何修改已生成的任务实例？ <a class="header-anchor" href="#q-如何修改已生成的任务实例" aria-label="Permalink to &quot;Q：如何修改已生成的任务实例？&quot;">​</a></h3><p>A：每个任务实例都是独立的，可以单独编辑：</p><ul><li>打开任务详情页</li><li>切换到「任务实例」标签页</li><li>点击需要修改的实例</li><li>编辑后保存，不影响其他实例</li></ul><h3 id="q-重复任务可以设置不同的负责人吗" tabindex="-1">Q：重复任务可以设置不同的负责人吗？ <a class="header-anchor" href="#q-重复任务可以设置不同的负责人吗" aria-label="Permalink to &quot;Q：重复任务可以设置不同的负责人吗？&quot;">​</a></h3><p>A：可以，有以下方式：</p><ul><li>设置默认负责人，所有实例分配给同一人</li><li>使用负责人轮换规则，自动轮换负责人</li><li>手动为每个实例分配不同的负责人</li></ul><h3 id="q-如何跳过某次重复任务" tabindex="-1">Q：如何跳过某次重复任务？ <a class="header-anchor" href="#q-如何跳过某次重复任务" aria-label="Permalink to &quot;Q：如何跳过某次重复任务？&quot;">​</a></h3><p>A：有以下方法：</p><ul><li>在任务实例列表中，点击「跳过」按钮</li><li>在重复规则中设置排除日期</li><li>暂时停止重复任务，需要时再恢复</li></ul><h3 id="q-重复任务会占用系统资源吗" tabindex="-1">Q：重复任务会占用系统资源吗？ <a class="header-anchor" href="#q-重复任务会占用系统资源吗" aria-label="Permalink to &quot;Q：重复任务会占用系统资源吗？&quot;">​</a></h3><p>A：重复任务会占用一定的系统资源，建议：</p><ul><li>合理设置重复频率，避免过于频繁</li><li>定期清理已完成的历史实例</li><li>避免创建过多重复任务</li></ul><h2 id="相关文档" tabindex="-1">相关文档 <a class="header-anchor" href="#相关文档" aria-label="Permalink to &quot;相关文档&quot;">​</a></h2><ul><li><a href="/using-system/task-management/create-task/">创建/编辑任务</a></li><li><a href="/using-system/task-management/reminders.html">任务提醒</a></li><li><a href="/using-system/task-management/execute.html">任务执行</a></li></ul>',77)])])}const q=a(e,[["render",o]]);export{c as __pageData,q as default};
